#!/usr/bin/env bash
# Baseline smoke test for harness v3.0.0 cycle.
# Generated by the initializer agent -- edit to match your project.
set -e

PROJECT_ROOT="$(cd "$(dirname "$0")/.." && pwd)"
SCRIPTS_DIR="$PROJECT_ROOT/plugins/harness/scripts"
HOOKS_DIR="$PROJECT_ROOT/plugins/harness/hooks"

echo "=== Harness v3.0.0 Baseline Smoke Test ==="

# 1. Verify Node.js is available
if command -v node > /dev/null 2>&1; then
  NODE_VERSION=$(node --version)
  echo "OK -- Node.js available ($NODE_VERSION)"
else
  echo "FAIL -- Node.js not found in PATH"
  exit 1
fi

# 2. Verify scripts directory exists
if [ -d "$SCRIPTS_DIR" ]; then
  echo "OK -- scripts directory exists"
else
  echo "FAIL -- scripts directory not found at $SCRIPTS_DIR"
  exit 1
fi

# 3. Verify harness-companion.mjs entry point exists and parses
if [ -f "$SCRIPTS_DIR/harness-companion.mjs" ]; then
  echo "OK -- harness-companion.mjs exists"
else
  echo "FAIL -- harness-companion.mjs not found"
  exit 1
fi

if node --check "$SCRIPTS_DIR/harness-companion.mjs" 2>/dev/null; then
  echo "OK -- harness-companion.mjs parses cleanly"
else
  echo "FAIL -- harness-companion.mjs has syntax errors"
  exit 1
fi

# 4. Verify all 7 lib modules (pre-v3.0.0 baseline -- events.mjs and metrics.mjs still present)
LIBS="state.mjs features.mjs git.mjs artifacts.mjs progress.mjs metrics.mjs events.mjs"
for lib in $LIBS; do
  if [ -f "$SCRIPTS_DIR/lib/$lib" ]; then
    echo "OK -- lib/$lib exists"
  else
    echo "FAIL -- lib/$lib not found"
    exit 1
  fi
done

# 5. Verify harness state files exist
if [ -f "$PROJECT_ROOT/.harness/features.json" ] && [ -f "$PROJECT_ROOT/.harness/state.json" ]; then
  echo "OK -- harness state files present"
else
  echo "FAIL -- harness state files missing"
  exit 1
fi

# 6. Verify hooks.json exists
if [ -f "$HOOKS_DIR/hooks.json" ]; then
  echo "OK -- hooks.json exists"
else
  echo "FAIL -- hooks.json not found at $HOOKS_DIR/hooks.json"
  exit 1
fi

# 7. Verify harness-companion.mjs responds to --help
if node "$SCRIPTS_DIR/harness-companion.mjs" --help > /dev/null 2>&1; then
  echo "OK -- harness-companion.mjs --help responds"
else
  echo "FAIL -- harness-companion.mjs --help did not respond"
  exit 1
fi

# 8. Verify features.json is valid JSON with expected feature count
FEATURE_COUNT=$(node -e "
  const fs = require('fs');
  const data = JSON.parse(fs.readFileSync('$PROJECT_ROOT/.harness/features.json', 'utf8'));
  console.log(data.features.length);
")
if [ "$FEATURE_COUNT" -eq 8 ]; then
  echo "OK -- features.json has 8 features"
else
  echo "FAIL -- features.json has $FEATURE_COUNT features (expected 8)"
  exit 1
fi

# 9. Verify state.json round is 0
CURRENT_ROUND=$(node -e "
  const fs = require('fs');
  const data = JSON.parse(fs.readFileSync('$PROJECT_ROOT/.harness/state.json', 'utf8'));
  console.log(data.current_round);
")
if [ "$CURRENT_ROUND" -eq 0 ]; then
  echo "OK -- state.json current_round is 0"
else
  echo "FAIL -- state.json current_round is $CURRENT_ROUND (expected 0)"
  exit 1
fi

echo ""
echo "Baseline verified. Ready for sprint."
